class Solution:
    def maximizeXor(self, nums, queries):
        BITS = 30
        nums_sorted = sorted(nums)
        order = sorted(range(len(queries)), key=lambda i: queries[i][1])
        answer = [-1] * len(queries)
        trie = {}
        idx = 0
        n = len(nums_sorted)
        for qi in order:
            x, m = queries[qi]
            while idx < n and nums_sorted[idx] <= m:
                node = trie
                v = nums_sorted[idx]
                for b in range(BITS, -1, -1):
                    bit = (v >> b) & 1
                    node = node.setdefault(bit, {})
                idx += 1
            if not trie:
                answer[qi] = -1
                continue
            node = trie
            best = 0
            for b in range(BITS, -1, -1):
                bit = (x >> b) & 1
                want = 1 - bit
                if want in node:
                    best |= (1 << b)
                    node = node[want]
                else:
                    node = node[bit]
            answer[qi] = best
        return answer

