var maximizeXor = function(nums, queries) {
    const BITS = 30;
    const numsSorted = nums.slice().sort((a, b) => a - b);
    const order = queries.map((_, i) => i).sort((a, b) => queries[a][1] - queries[b][1]);
    const answer = new Array(queries.length).fill(-1);
    const root = {};
    let idx = 0;
    const n = numsSorted.length;
    let hasAny = false;
    for (const qi of order) {
        const x = queries[qi][0];
        const m = queries[qi][1];
        while (idx < n && numsSorted[idx] <= m) {
            let node = root;
            const v = numsSorted[idx];
            for (let b = BITS; b >= 0; b--) {
                const bit = (v >> b) & 1;
                if (!(bit in node)) node[bit] = {};
                node = node[bit];
            }
            hasAny = true;
            idx++;
        }
        if (!hasAny) {
            answer[qi] = -1;
            continue;
        }
        let node = root;
        let best = 0;
        for (let b = BITS; b >= 0; b--) {
            const bit = (x >> b) & 1;
            const want = 1 - bit;
            if (want in node) {
                best |= (1 << b);
                node = node[want];
            } else {
                node = node[bit];
            }
        }
        answer[qi] = best;
    }
    return answer;
};
